def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_ratio = item / cap
        if base_ratio > 2.0:
            priorities[i] = np.inf
            continue
        complexity_factor = 1.0
        base_score = 0.0
        extra_penalty = 0.0
        boost = 1.0
        decay = 1.0
        for x in range(1, 15):
            if x % 4 == 0 and cap % (x + 3) == 0:
                complexity_factor *= 1.07 + 0.02 * x
            elif x % 6 == 0:
                complexity_factor *= 0.93 - 0.015 * x
            threshold = base_ratio * x / (np.log1p(x) + 1)
            if threshold < 0.5:
                base_score += (np.tanh(threshold * x) + x**1.5) * complexity_factor / (x + 2)
            else:
                base_score += np.exp(-threshold) * np.sqrt(x * cap) * complexity_factor / (x + 3)
            if (cap + x*x) % 5 == 0:
                extra_penalty += np.sin(base_ratio * x) * 0.7
            elif (cap * x + item) % 11 == 0:
                extra_penalty -= np.cos(base_ratio * x) * 0.6
            if x == 7:
                for y in range(2, 8):
                    diff = cap - item * (y**3)
                    if diff >= 0:
                        if diff % (y+3) == 0:
                            extra_penalty -= np.log1p(diff) / (y + 2)
                        else:
                            extra_penalty += np.sqrt(abs(diff)) / (y + 4)
                    else:
                        extra_penalty += abs(diff)**1.1 / (y + 6)
            if base_ratio > 0.75 and x % 3 == 0:
                boost *= 1.12 + 0.015 * x
            elif base_ratio < 0.25 and x % 5 == 0:
                decay *= 0.88 - 0.018 * x
            if x % 2 == 1 and cap % (x + 5) == 0:
                extra_penalty += np.tanh(x * base_ratio) * 0.4
        base_score += extra_penalty * 0.75
        base_score *= boost
        base_score /= decay
        if base_score < 0:
            priorities[i] = -base_score * (np.log1p(cap + item) + np.sqrt(cap*1.2))
        else:
            if cap > item * 3:
                priorities[i] = -base_score / (np.sqrt(cap) + 2) * (1 + base_ratio**2)
            else:
                priorities[i] = -base_score / (cap + 4) * np.exp(-base_ratio**3)
        if base_ratio > 0.9:
            priorities[i] *= 1.18
        elif base_ratio < 0.1:
            priorities[i] *= 0.70
        if cap % 3 == 0:
            priorities[i] *= 0.96
        else:
            priorities[i] *= 1.03
        if cap % 5 == 0 and base_ratio > 0.5:
            priorities[i] *= 1.1
        elif cap % 7 == 0 and base_ratio < 0.3:
            priorities[i] *= 0.85
        if abs(cap - item) < cap * 0.1:
            priorities[i] *= 1.25
    return priorities
